(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var requestBody = request.body.data;

    var incidentSysId = requestBody.incident_sys_id;
    var workNote = requestBody.work_note;

    if (!incidentSysId || !workNote) {
        response.setStatus(400);
        return { status: "error", message: "Missing required fields: incident_sys_id or work_note" };
    }

    var incidentGR = new GlideRecord('incident');
    if (!incidentGR.get(incidentSysId)) {
        response.setStatus(404);
        return { status: "error", message: "Incident not found with given sys_id" };
    }

    incidentGR.work_notes = workNote;
    incidentGR.update();

    // Fetch the newly created work note sys_id
    var journalGR = new GlideRecord('sys_journal_field');
    journalGR.addQuery('element_id', incidentSysId);
    journalGR.addQuery('element', 'work_notes');
    journalGR.addQuery('value', workNote);
    journalGR.orderByDesc('sys_created_on');
    journalGR.setLimit(1);
    journalGR.query();

    var noteSysId = null;
    if (journalGR.next()) {
        noteSysId = journalGR.getUniqueValue();
    }

    response.setStatus(200);
    return {
        status: "success",
        message: "Work note added successfully",
        sys_id: noteSysId
    };
})(request, response);
